1355	/* Build a structured $rc record and store it in the "rc" variable.
1356	 * run_code: 0=ok, 1=not-found, 2=crash, 3=exec-failure, 4=usage-error
1357	 * detail: prog exit code (run_code=0) or error code (others)
1358	 * msg: human-readable message (NULL for success case)
1359	 * kind: category string */
1360	int set_rc_record(int run_code, int detail, char *msg, char *kind) {
1361	    int rec = val_new_rec();
1362	    if (rec < 0) return -1;
1363	
1364	    /* $rc.run */
1365	    int fn_run = val_new_str("run");
1366	    int fv_run = val_new_int(run_code);
1367	    val_rec_set(rec, fn_run, fv_run);
1368	
1369	    /* $rc.kind */
1370	    int fn_kind = val_new_str("kind");
1371	    int fv_kind = val_new_str(kind);
1372	    val_rec_set(rec, fn_kind, fv_kind);
1373	
1374	    if (run_code == 0) {
1375	        /* Success: $rc.prog = detail */
1376	        int fn_prog = val_new_str("prog");
1377	        int fv_prog = val_new_int(detail);
1378	        val_rec_set(rec, fn_prog, fv_prog);
1379	    } else {
1380	        /* Failure: $rc.err and $rc.msg */
1381	        int fn_err = val_new_str("err");
1382	        int fv_err = val_new_int(detail);
1383	        val_rec_set(rec, fn_err, fv_err);
1384	        int fn_msg = val_new_str("msg");
1385	        int fv_msg = val_new_str(msg);
1386	        val_rec_set(rec, fn_msg, fv_msg);
1387	    }
1388	
1389	    env_set("rc", rec);
1390	    rc_defined = 1;
1391	    return 0;
1392	}
