1433	/* Path concatenation: join cwd and relative path into buf.
1434	 * If path starts with '/', it's absolute — copy directly.
1435	 * Otherwise, append to cwd. Returns buf. */
1436	char *fs_resolve(char *path, char *buf) {
1437	    if (path[0] == 47) { /* '/' — absolute */
1438	        str_copy(buf, path);
1439	        return buf;
1440	    }
1441	    /* Relative: cwd + '/' + path */
1442	    int i = 0;
1443	    while (fs_cwd[i] && i < MAX_PATH_LEN - 2) {
1444	        buf[i] = fs_cwd[i];
1445	        i = i + 1;
1446	    }
1447	    /* Add separator if cwd doesn't end with '/' */
1448	    if (i > 0 && buf[i - 1] != 47) {
1449	        buf[i] = 47;
1450	        i = i + 1;
1451	    }
1452	    int j = 0;
1453	    while (path[j] && i < MAX_PATH_LEN - 1) {
1454	        buf[i] = path[j];
1455	        i = i + 1;
1456	        j = j + 1;
1457	    }
1458	    buf[i] = 0;
1459	    return buf;
1460	}
