int cmd_cd() {
    if (expand_count < 2) {
        uart_puts("error: cd: expected path argument");
        uart_newline();
        return RET_ERR;
    }
    char *path = exp_str(1);
    int r = fs_chdir(path);
    if (r < 0) {
        uart_puts("error: cd: no such directory: ");
        uart_puts(path);
        uart_newline();
        return RET_ERR;
    }
    last_result = val_new_str(fs_cwd);
    return RET_OK;
}

int cmd_pwd() {
    char buf[MAX_PATH_LEN];
    fs_getcwd(buf);
    uart_puts(buf);
    uart_newline();
    last_result = val_new_str(buf);
    return RET_OK;
}

